def generate_jwt_token(username, token_type='web'):
    payload = {
        'username': username,
        'token_type': token_type,
        'iat': datetime.utcnow(),
        'exp': datetime.utcnow() + timedelta(hours=24)
    }
    return jwt.encode(payload, JWT_SECRET, algorithm=JWT_ALGORITHM)


def decode_jwt_token(token):
    try:
        payload = jwt.decode(token, JWT_SECRET, algorithms=[JWT_ALGORITHM])
        return payload
    except jwt.ExpiredSignatureError:
        return None
    except jwt.InvalidTokenError:
        return None


def login_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        if 'username' not in session or not session.get('authenticated'):
            return redirect(url_for('login'))
        return f(*args, **kwargs)
    return decorated_function


def api_auth_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization', '')

        if auth_header.startswith('Bearer '):
            token = auth_header[7:]
            payload = decode_jwt_token(token)
            if payload:
                request.api_user = payload['username']
                return f(*args, **kwargs)

        api_key = request.headers.get('X-API-Key', '')
        if api_key and api_key in api_keys_db:
            request.api_user = api_keys_db[api_key]
            return f(*args, **kwargs)

        return jsonify({'error': 'Authentication required'}), 401
    return decorated_function


@app.route('/')
def index():
    if 'username' in session and session.get('authenticated'):
        return redirect(url_for('dashboard'))
    return redirect(url_for('login'))


@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'GET':
        return render_template_string(REGISTER_TEMPLATE, error=None)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '').strip()
    enable_mfa = request.form.get('enable_mfa') == 'on'

    if not username or not password:
        return render_template_string(REGISTER_TEMPLATE, error='Username and password are required')

    if username in users_db:
        return render_template_string(REGISTER_TEMPLATE, error='Username already exists')

    if len(password) < 8:
        return render_template_string(REGISTER_TEMPLATE, error='Password must be at least 8 characters')

    mfa_secret = None
    if enable_mfa:
        mfa_secret = pyotp.random_base32()

    users_db[username] = {
        'password_hash': generate_password_hash(password),
        'mfa_enabled': enable_mfa,
        'mfa_secret': mfa_secret,
        'created_at': datetime.utcnow().isoformat()
    }

    return render_template_string(LOGIN_TEMPLATE, error=None,
                                  message='Registration successful! Please login.')


@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'GET':
        return render_template_string(LOGIN_TEMPLATE, error=None, message=None)

    username = request.form.get('username', '').strip()
    password = request.form.get('password', '').strip()

    if not username or not password:
        return render_template_string(LOGIN_TEMPLATE, error='Username and password are required', message=None)

    user = users_db.get(username)
    if not user or not check_password_hash(user['password_hash'], password):
        return render_template_string(LOGIN_TEMPLATE, error='Invalid username or password', message=None)

    # Password verified - check MFA status
    if user['mfa_enabled'] and user['mfa_secret']:
        # MFA is enabled, store partial auth in session and prompt for OTP
        session['username'] = username
        session['authenticated'] = False
        session['mfa_pending'] = True
        return redirect(url_for('verify_mfa'))
    else:
        # MFA not enabled, grant access immediately
        session['username'] = username
        session['authenticated'] = True
        session['mfa_pending'] = False
        return redirect(url_for('dashboard'))


@app.route('/verify-mfa', methods=['GET', 'POST'])
def verify_mfa():
    if 'username' not in session or not session.get('mfa_pending'):
        return redirect(url_for('login'))

    if request.method == 'GET':
        return render_template_string(MFA_TEMPLATE, error=None)

    otp = request.form.get('otp', '').strip()
    username = session['username']
    user = users_db.get(username)

    if not user:
        session.clear()
        return redirect(url_for('login'))

    totp = pyotp.TOTP(user['mfa_secret'])
    if totp.verify(otp, valid_window=1):
        session['authenticated'] = True
        session['mfa_pending'] = False
        return redirect(url_for('dashboard'))
    else:
        return render_template_string(MFA_TEMPLATE, error='Invalid OTP code. Please try again.')


@app.route('/dashboard')
@login_required
def dashboard():
    username = session['username']
    user = users_db.get(username)

    user_api_key = None
    for key, uname in api_keys_db.items():
        if uname == username:
            user_api_key = key
            break

    return render_template_string(
        DASHBOARD_TEMPLATE,
        username=username,
        mfa_enabled=user['mfa_enabled'],
        mfa_secret=user.get('mfa_secret') if user['mfa_enabled'] else None,
        mfa_uri=pyotp.TOTP(user['mfa_secret']).provisioning_uri(
            name=username, issuer_name='FlaskAuthApp'
        ) if user['mfa_enabled'] and user.get('mfa_secret') else None,
        api_key=user_api_key
    )


@app.route('/enable-mfa')
@login_required
def enable_mfa():
    username = session['username']
    user = users_db.get(username)

    if user['mfa_enabled']:
        # Disable MFA
        user['mfa_enabled'] = False
        user['mfa_secret'] = None
        return redirect(url_for('dashboard'))
    else:
        # Setup MFA
        secret = pyotp.random_base32()
        session['pending_mfa_secret'] = secret
        uri = pyotp.TOTP(secret).provisioning_uri(name=username, issuer_name='FlaskAuthApp')
        return render_template_string(SETUP_MFA_TEMPLATE, secret=secret, uri=uri)


@app.route('/confirm-mfa', methods=['POST'])
@login_required
def confirm_mfa():
    username = session['username']
    user = users_db.get(username)
    pending_secret = session.get('pending_mfa_secret')

    if not pending_secret:
        return redirect(url_for('dashboard'))

    otp = request.form.get('otp', '').strip()
    totp = pyotp.TOTP(pending_secret)

    if totp.verify(otp, valid_window=1):
        user['mfa_enabled'] = True
        user['mfa_secret'] = pending_secret
        session.pop('pending_mfa_secret', None)
        return redirect(url_for('dashboard'))
    else:
        uri = totp.provisioning_uri(name=username, issuer_name='FlaskAuthApp')
        return render_template_string(SETUP_MFA_TEMPLATE, secret=pending_secret, uri=uri)


@app.route('/generate-api-key')
@login_required
def generate_api_key():
    username = session['username']

    # Remove existing API key for this user
    keys_to_remove = [k for k, v in api_keys_db.items() if v == username]
    for k in keys_to_remove:
        del api_keys_db[k]

    # Generate new API key
    api_key = secrets.token_urlsafe(32)
    api_keys_db[api_key] = username

    return redirect(url_for('dashboard'))


@app.route('/logout')
def logout():
    session.clear()
    return redirect(url_for('login'))


