@app.route('/api/login', methods=['POST'])
def api_login():
    """Standard API login - respects MFA if enabled."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '').strip()
    otp = data.get('otp', '').strip()

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    user = users_db.get(username)
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid username or password'}), 401

    # Check MFA
    if user['mfa_enabled'] and user['mfa_secret']:
        if not otp:
            return jsonify({
                'error': 'MFA required',
                'mfa_required': True,
                'message': 'Please provide OTP in the otp field'
            }), 403

        totp = pyotp.TOTP(user['mfa_secret'])
        if not totp.verify(otp, valid_window=1):
            return jsonify({'error': 'Invalid OTP code', 'mfa_required': True}), 401

    token = generate_jwt_token(username, token_type='api')
    return jsonify({
        'message': 'Login successful',
        'token': token,
        'username': username,
        'mfa_verified': user['mfa_enabled']
    })


@app.route('/api/direct-login', methods=['POST'])
def api_direct_login():
    """
    Direct login endpoint for API clients and automated scripts.
    Skips MFA checks - authenticates with username/password or API key only.
    """
    # Check for API key authentication first
    api_key = request.headers.get('X-API-Key', '')
    if api_key:
        if api_key in api_keys_db:
            username = api_keys_db[api_key]
            token = generate_jwt_token(username, token_type='api_direct')
            return jsonify({
                'message': 'Login successful via API key',
                'token': token,
                'username': username,
                'auth_method': 'api_key',
                'mfa_skipped': True
            })
        else:
            return jsonify({'error': 'Invalid API key'}), 401

    # Username/password authentication (no MFA)
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body or X-API-Key header required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '').strip()

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    user = users_db.get(username)
    if not user or not check_password_hash(user['password_hash'], password):
        return jsonify({'error': 'Invalid username or password'}), 401

    # Skip MFA - grant access immediately after password verification
    token = generate_jwt_token(username, token_type='api_direct')
    return jsonify({
        'message': 'Login successful (MFA skipped for API access)',
        'token': token,
        'username': username,
        'auth_method': 'password',
        'mfa_skipped': True if user['mfa_enabled'] else False
    })


@app.route('/api/register', methods=['POST'])
def api_register():
    """API endpoint to register a new user."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'JSON body required'}), 400

    username = data.get('username', '').strip()
    password = data.get('password', '').strip()
    enable_mfa = data.get('enable_mfa', False)

    if not username or not password:
        return jsonify({'error': 'Username and password are required'}), 400

    if username in users_db:
        return jsonify({'error': 'Username already exists'}), 409

    if len(password) < 8:
        return jsonify({'error': 'Password must be at least 8 characters'}), 400

    mfa_secret = None
    if enable_mfa:
        mfa_secret = pyotp.random_base32()

    users_db[username] = {
        'password_hash': generate_password_hash(password),
        'mfa_enabled': enable_mfa,
        'mfa_secret': mfa_secret,
        'created_at': datetime.utcnow().isoformat()
    }

    response = {
        'message': 'Registration successful',
        'username': username,
        'mfa_enabled': enable_mfa
    }

    if enable_mfa and mfa_secret:
        response['mfa_secret'] = mfa_secret
        response['mfa_uri'] = pyotp.TOTP(mfa_secret).provisioning_uri(
            name=username, issuer_name='FlaskAuthApp'
        )

    return jsonify(response), 201


