@app.route('/api/user/toggle-mfa', methods=['POST'])
@api_auth_required
def api_toggle_mfa():
    """Enable or disable MFA for the authenticated user."""
    username = request.api_user
    user = users_db.get(username)
    if not user:
        return jsonify({'error': 'User not found'}), 404

    data = request.get_json() or {}

    if user['mfa_enabled']:
        # Disable MFA
        user['mfa_enabled'] = False
        user['mfa_secret'] = None
        return jsonify({'message': 'MFA disabled', 'mfa_enabled': False})
    else:
        # Enable MFA
        otp = data.get('otp', '').strip()
        pending_secret = data.get('pending_secret', '').strip()

        if not pending_secret:
            # Generate new secret
            new_secret = pyotp.random_base32()
            uri = pyotp.TOTP(new_secret).provisioning_uri(
                name=username, issuer_name='FlaskAuthApp'
            )
            return jsonify({
                'message': 'MFA setup initiated. Add secret to your authenticator app and confirm with OTP.',
                'mfa_secret': new_secret,
                'mfa_uri': uri,
                'next_step': 'POST with pending_secret and otp fields to confirm'
            })
        else:
            # Confirm MFA setup
            if not otp:
                return jsonify({'error': 'OTP required to confirm MFA setup'}), 400

            totp = pyotp.TOTP(pending_secret)
            if totp.verify(otp, valid_window=1):
                user['mfa_enabled'] = True
                user['mfa_secret'] = pending_secret
                return jsonify({'message': 'MFA enabled successfully', 'mfa_enabled': True})
            else:
                return jsonify({'error': 'Invalid OTP'}), 401


@app.route('/api/generate-api-key', methods=['POST'])
@api_auth_required
def api_generate_key():
    """Generate a new API key for the authenticated user."""
    username = request.api_user

    # Remove existing keys for this user
    keys_to_remove = [k for k, v in api_keys_db.items() if v == username]
    for k in keys_to_remove:
        del api_keys_db[k]

    api_key = secrets.token_urlsafe(32)
    api_keys_db[api_key] = username

    return jsonify({
        'message': 'API key generated successfully',
        'api_key': api_key,
        'username': username
    })


